var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"또 무슨 난리래? 침식체라도 나타났나?","JPN":"何だ？　また侵食体でも現れたのか？","ENG":"What's going on? Is there another C.O. attack?","TWN":"又在吵什麼？出現侵蝕體嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"경찰들 하는 얘기를 들었는데 용병들이 총격전을 벌였대. 한동안 잠잠하더니 또 이러네.","JPN":"警察の話を聞いたんだけど、傭兵が銃撃戦をしたんだって。しばらく大人しいと思ったらまたこれだ。","ENG":"I heard the cops talking and it seems like the mercenaries had a gunfight. Can't believe they're starting this again.","TWN":"聽警察說是傭兵發生槍戰，我才想說這陣子安靜不少，結果又來啦！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"거기 찍지 마세요! 찍으시면 안 됩니다!","JPN":"そこ、撮らないでください！　撮影は禁止です！","ENG":"Hey! You're not allowed to film this! Stop filming!","TWN":"請不要拍照，這裡不能拍照！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"옆 건물들도 붕괴될 수 있습니다! 사건 현장에 접근하지 말아 주세요!","JPN":"隣の建物も崩壊する可能性があります！　事件現場に近づかないでください！","ENG":"Please step away from the crime scene! It's not safe, the neighboring building may collapse as well!","TWN":"旁邊的建築物也可能會倒塌！請勿靠近案發現場！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"비키세요. 제 4 특별기동수사대에서 나온 이유미 경정입니다.","JPN":"どきなさい。第4特別機動捜査隊のカスカベ・ユミ警視です。","ENG":"Out of my way. I'm Major Lee Yumi of SWAT 4.","TWN":"請讓讓，我是第四特遣機動隊的李悠美警正。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 경정님. 마음 급하신 건 알지만 같은 공무원끼리 사이 좋게 지내야죠.","JPN":"はは、警視様。急いでいるのはわかりますけど、同じ公務員同士、仲良くしないと。","ENG":"Ha ha, Major! I know you're pressed for time, but you should get along with the other civil servants, too.","TWN":"哈哈，警正，我知道你很心急，但大家都是吃公家飯的，對人家客氣一點嘛～"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"담당하고 있는 실종 사건 때문에 왔어요. 여기서 일어난 폭발이랑 관련이 있어서요.","JPN":"担当している失踪事件で来ました。ここで発生した爆発と関係がありますので。","ENG":"I'm only here because of a missing persons case I'm working on. It seems as if the explosion here has some connection to it.","TWN":"我們是來調查一起失蹤案件的，與這裡發生的爆炸事件有關。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"크흠……. 어린 것이 까칠해선…….","JPN":"こほん……小娘のくせに可愛げがないな……","ENG":"Ahem...! Well aren't you a tiny little brat...","TWN":"咳咳……年紀輕輕說話沒大沒小的……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"건물은 아직 추가 붕괴 위험이 있습니다. 따라오세요.","JPN":"建物はまだ二次的な崩壊の危険性があります。ついてきてください。","ENG":"The building might be at risk of further collapse. Please follow me.","TWN":"大樓還有倒塌的危險，跟我來。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"그런데 실종자가 누구길래 4기동이 담당하는 겁니까?","JPN":"ところで、第4機動隊が担当するなんて、どんな失踪者なんですか？","ENG":"But who could the missing person be if SWAT 4 is on the case?","TWN":"不過失蹤的人是誰？竟然請到第四機動隊出馬。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"베로니카라는 이름의 여성입니다.","JPN":"ベロニカという名前の女性です。","ENG":"A woman named Veronica.","TWN":"是一位名叫貝洛妮卡的女性。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스라는 가사도우미 파견 업체의 사장이죠.","JPN":"フローラメイドサービスという家事代行派遣企業の社長です。","ENG":"She is the head of a housekeeping agency called Flora Maid Service.","TWN":"是一間名叫芙蘿拉女僕服務公司的家事幫手派遣業者的社長。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"직원 분이 이 근처에서 헤어졌는데 귀가하지 않았다고 해서 경찰에 신고했어요.","JPN":"職員の方が、この辺りで別れたのに帰ってこないと言って警察に通報したんですよ。","ENG":"One of her employee said she last saw her here, but when she didn't show up back home, she called the cops.","TWN":"員工說在這附近和她分開後，她一直沒回家，所以來報警。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>보통 사람은 메이드장님에게 못 당하지 말임다!</color> 라고 하는 바람에 저희 쪽으로 사건이 이관됐죠.","JPN":"<color=#ffd34c>普通の人間はメイド長に勝てないっす！</color>と言ったせいで、私たちの方に事件が移管されました。","ENG":"We were put on this case after the employee said, <color=#ffd34c>\\"A normal person can't hurt Chief Maid, ma'am!\\"</color>","TWN":"<color=#ffd34c>普通人才打不過女僕長咧！</color>因為報案人這樣說，所以案子就轉到我們手上囉。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"애 말을 믿다니 제정신인지 모르겠어.","JPN":"子どもの話を信じるなんて、頭がどうかしてるわ。","ENG":"I can't believe that you really trust what a child said.","TWN":"真不知道腦袋在想什麼，竟然相信一個孩子說的話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하여튼 매스컴에 관심 끌 때만 추켜세우지, 우릴 잡일꾼으로 보는 건 그대로라니까.","JPN":"まったく、マスコミの関心を引こうって時だけ大々的にするけど、私たちを雑用係程度としか考えていないのは相変わらずよね。","ENG":"Anyway, we're only being praised to attract the attention of the media. The rest of the time, our position isn't that different.","TWN":"總之只有媒體關注時才會吹捧我們，大家一樣把我們當成是打雜的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"하하…… 고생이 많으시군요.","JPN":"はは……ご苦労様です。","ENG":"Haha... That sounds rough.","TWN":"哈哈……那就麻煩你們囉。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"그럼 저는 다른 일이 있어서 이만 가 보겠습니다. 추가 붕괴 우려가 있으니 조심해서 둘러 보세요.","JPN":"それでは私は他に仕事があるのでこれで失礼します。二次崩壊の恐れがありますので、気をつけて見て回ってください。","ENG":"Well, I have somewhere else to be, so I'll leave you here. Oh, and be careful. The building could collapse even more.","TWN":"我還有其他事要先離開，調查時要小心點，大樓很可能會再坍塌。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어때, 강소영 경위? 뭐 좀 눈에 띄어?","JPN":"どう？　マエカワ警部補。何か目に付くものはある？","ENG":"How's it looking, Lieutenant Kang? Anything catch your eye?","TWN":"怎麼樣，姜素英警員？有看到什麼蛛絲馬跡嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L38_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"글쎄요. 일단은 아무래도……","JPN":"そうですね。とりあえず……","ENG":"I don't know. Not yet, I guess...","TWN":"這個嘛，好像……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"……읏차. 찾았다.","JPN":"……よいしょっと。見つけた。","ENG":"Hup...! There it is.","TWN":"……嘿嘿，找到囉！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"여기 보세요, 경정님. 이 불탄 회로가 뭔지 알아 보시겠어요?","JPN":"ここ見てください、警視様。この焼けた回路が何かわかります？","ENG":"Look at this, Major. Doesn't that burnt circuit look familiar?","TWN":"警正你看，你認得出來這個著火的線路嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"기억나. 민병대들을 추적할 때도 사건 현장에서 비슷한 것들이 현장에서 발견됐지?","JPN":"見覚えがあるわ。民兵隊を追跡したときにも事件現場で似たようなものが発見されたわよね？","ENG":"I remember that. Didn't we find a similar one on another case while chasing after the Militia?","TWN":"我記得，我們在追捕民兵隊時，也曾在案發現場發現類似的東西對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"맞아요. 보고서에도 그 중 한 명이 폭발물 다루는 데 능숙하다고 적혀 있었고요.","JPN":"そのとおりです。報告書にも民兵隊のうちの一人が爆発物に精通しているって書いてありました。","ENG":"Correct. According to the report, they have someone who's experienced in handling explosives.","TWN":"沒錯，報告中也有提到，他們其中一個人擅長控制爆裂物。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무래도 이 현장은 민병대들 소행이 맞는 것 같네요.","JPN":"どうやらこの現場は民兵隊の仕業に間違いないようですね。","ENG":"It would seem like the Militia was behind this.","TWN":"看來是民兵隊幹的好事沒錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 베로니카란 사람, 신원 검색 했을 때 관리국 명의로 전부 열람이 안 됐지?","JPN":"あのベロニカって人、身元を検索したときに管理局名義になっていて何も出なかったんだよね？","ENG":"That Veronica person, all her files were blocked off by the Administration when you tried to do a background check, right?","TWN":"那個叫貝洛妮卡的人，在確認她的身分時，用管理局的名義完全無法查閱對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네. 윗분들은 뭔가 알고 계신 것 같던데……","JPN":"はい。上層部は何か知っているようでしたけど……","ENG":"Yes. I'm sure the higher-ups know something we don't...","TWN":"對，上面的人好像知道些什麼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아무리 졸라도 묵비권을 행사하시더라고요, 아하하.","JPN":"いくらねだっても黙秘権を行使されちゃって、あはは。","ENG":"But they wouldn't budge no matter how much I begged, ah hah hah.","TWN":"但不管我怎麼盧，他們就是堅決行使緘默權，哈哈哈。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"실종자가 CCTV에서 사라진 시각과 건물이 무너진 시각도 가까워.","JPN":"失踪者がCCTVから消えた時刻と建物が崩れた時刻も近い。","ENG":"The moment she disappears from the security cameras and the moment the building collapsed are not very far apart.","TWN":"而且失蹤的人消失在CCTV上的時間，和大樓倒塌的時間非常相近，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"보나마나 민병대 짓이 틀림없어! 이번에야말로 그 무법자들을 철창에 처넣는 거야!","JPN":"民兵隊の仕業で間違いないわ！　今度こそあの無法者たちを刑務所行きにしてやる！","ENG":"It has to be the Militia's doing! It's time we put those outlaws behind bars!","TWN":"看來就是民兵隊幹的沒錯！我這次一定要把那些罪犯關進牢裡！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그치만 예전에 수사할 때도 결국 빈손으로 끝난 걸요?","JPN":"でもこの前に捜査したときにも結局収穫なしでしたよ？","ENG":"But didn't we try that before and ended up with nothing?","TWN":"可是之前調查時，到最後還是空手而歸欸？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……아, 아무튼! 그런 패배주의는 경찰로서 실격이야, 강소영 경위!","JPN":"……と、とにかく！　そんな敗北主義は警察として失格よ、マエカワ警部補！","ENG":"A-anyway! That kind of attitude will not be accepted in this police force, Lieutenant Kang!","TWN":"…總…總之！失敗主義者是沒資格當警察的，姜素英員警！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하아……. 그 난리를 겪었는데도 여전히 경위라니, 제 신세도 참.","JPN":"はあ……あれほど苦労したのにまだ警部補だなんて、私の人生っていったい。","ENG":"*Sigh...* I can't believe I'm still a lieutenant even after all that I went through...","TWN":"哀……經過那一場混亂，結果我還是個小小員警，我也太悲慘。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"잠깐 기다려 보세요.","JPN":"ちょっと待ってくださいね。","ENG":"Hold on.","TWN":"先等一下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"응? 지금 어디에 전화 거는 거야?","JPN":"うん？　どこに電話してるの？","ENG":"Hmm? Who are you calling?","TWN":"嗯？你現在是要打電話給誰？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"원래 세상은 서로 돕고 사는 거 아니겠어요?","JPN":"世の中お互いに助け合って生きていくものじゃないですか。","ENG":"Aren't we all supposed to look out for one another in this world?","TWN":"人家說出外靠朋友的嘛～"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"잠깐, 경위! 그 번호 설마……!","JPN":"ちょっと、警部補！　その番号はまさか……！","ENG":"Wait, Lieutenant! You're not calling...?!","TWN":"等等，姜素英員警！那個號碼該不會是……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그렇지 않아도 지난 일로 보답드리려 했는데 먼저 연락해 주셨네요, 형사님.","JPN":"ちょうど先日のことでお礼をしなければと思っていたのですが、連絡をいただいてしまいましたね、刑事さん。","ENG":"Hello officer. I've been meaning to call you to repay you for last time.","TWN":"姜警官，之前的事我正想報答你們呢，你倒先打給我啦。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"회장님께서는 현재 중요한 업무로 부재 중이십니다.","JPN":"会長はただいま重要な業務のため留守にしております。","ENG":"The President is currently unavailable due to some urgent business.","TWN":"會長現在有要事在身，不在公司裡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어떤 용건 때문이신지, 먼저 여쭤 봐도 될까요?","JPN":"どのようなご用件かまずお伺いしてもよろしいでしょうか？","ENG":"May I ask you why you called?","TWN":"我可以先問問，是什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};